                <span className="mr-3 text-gray-400">We Install</span>
                <span className="text-brand-red">{text}</span>
                <span className="w-1 h-8 md:h-10 bg-brand-red ml-1 animate-pulse"></span>
              </div>

              <p className="text-lg md:text-xl text-gray-600 mb-8 max-w-lg font-medium leading-relaxed">
