              </p>

              <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                  <a href="#contact" className="flex items-center justify-center gap-2 bg-brand-red text-white px-8 py-4 rounded font-bold uppercase tracking-widest text-xs hover:bg-red-700 transition-all hover:shadow-lg shadow-md transform hover:-translate-y-0.5">
                    <Calendar size={16} /> Book Installation
                  </a>
                  <a href="tel:+263774944694" className="flex items-center justify-center gap-2 bg-white text-brand-black border border-gray-200 px-8 py-4 rounded font-bold uppercase tracking-widest text-xs hover:bg-gray-50 transition-all hover:shadow-lg shadow-sm transform hover:-translate-y-0.5">
                    <Phone size={16} /> Call Now
                  </a>
              </div>
           </div>

           {/* Right Content: Image Carousel */}
           <div className="lg:col-span-6 relative">
              {/* Removed border-4 border-white */}
              <div className="relative w-full aspect-[4/3] rounded-2xl shadow-2xl overflow-hidden bg-gray-200">
                {images.map((img, index) => (
                  <div 
                    key={index}
                    className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${index === currentSlide ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}
                  >
                    <img 
